    currency: 'EUR',
    minimumFractionDigits: 2
  }).format(price);
};

function OrderConfirmation() {
  const { state } = useLocation();
  const { orderId, cart } = state;
  const total = cart.reduce((sum, item) => sum + (parseFloat(item.price) * item.quantity), 0);



